{"code": "import json

# Load the full funding data
funding_path = "var_functions.query_db:32"
funding_data = None

# Try to read as a file first
try:
    with open(funding_path, 'r') as f:
        funding_data = json.load(f)
    print("Loaded funding data from file")
except:
    # If it's not a file path, it might be stored as a JSON string
    try:
        funding_data = json.loads(funding_path.replace("'", '"'))
        print("Loaded funding data from string")
    except:
        print("Could not load funding data")

# Check what we have
if funding_data:
    print(f"Total funding records: {len(funding_data)}")
    print("Sample records:")
    for i, record in enumerate(funding_data[:3]):
        print(f"  {i+1}. {record['Project_Name']} - ${record['Amount']}")
else:
    print("No funding data loaded")"}

